const now = new Date();
const d6m = new Date(now); d6m.setDate(now.getDate() - 180);
const d7m = new Date(now); d7m.setDate(now.getDate() - 210);
const fmt = d => parseInt(`${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}`);
return [{ json: { desde: fmt(d7m), hasta: fmt(d6m) } }];

const item = $input.item.json;
const mensaje = `✨ Hola ${item.Nombre}, han pasado más de 6 meses desde tu última limpieza dental.\n\nTus dientes te lo agradecerán 😊 ¿Te buscamos un hueco esta semana para tu revisión e higiene?`;
return [{ json: { ...item, mensaje } }];
